('4bcb12cc-a558-42b5-87b2-4df2ede9a7b1','いつ～ますか','いつ～ますか','N5','いつ～ますか','いつ [动]ますか いつ：何时？ 不能加“に” 询问具体时间：“何時に”','いつ [动]ますか いつ：何时？ 不能加“に” 询问具体时间：“何時に”',NULL,8),
('1d3c6bd2-6418-467c-88d8-890b1eadc380','今～時～分です','今～時～分です','N5','今～時～分です','今～時～分です。','今～時～分です。',NULL,9),
('1c9583fb-65ea-4243-86ec-5c2a72abcd01','～か～','～か～','N5','～か～','[名A]+か+[名B]：表示选择，“A或B”。','[名A]+か+[名B]：表示选择，“A或B”。',NULL,10),
('c2d31a97-aa94-4d97-bacc-5213cb6c90a6','～が，～ [转折]','～が，～ [转折]','N4','～が，～ [转折]','[小句]が、[小句]：[转折] 连接两个小句，表示转折，“可是，但是”。','[小句]が、[小句]：[转折] 连接两个小句，表示转折，“可是，但是”。',NULL,11),
('d981e7ce-e685-46e3-a92c-e7d6f895a6f8','～が，～ [铺垫]','～が，～ [铺垫]','N4','～が，～ [铺垫]','[小句]が、[小句]：[铺垫]','[小句]が、[小句]：[铺垫]',NULL,12),
('5a4456c9-2e33-451f-9d76-b0ac9055f369','～が～','～が～','N4','～が～','提示主语。旧信息用“は”，新信息用“が”。疑问词作主语时，一定用“が”（新信息）。','提示主语。旧信息用“は”，新信息用“が”。疑问词作主语时，一定用“が”（新信息）。',NULL,13),
('479d992a-630c-414b-98e5-a56826dbd3e0','～が～です','～が～です','N4','～が～です','[名词]が　[动词] 中立叙述（叙述直接观察的事物）','[名词]が　[动词] 中立叙述（叙述直接观察的事物）',NULL,14),
('e5a9f224-256c-4d31-aeb4-11673b30476d','～か～(では)ないか～','～か～(では)ないか～','N4','～か～(では)ないか～','形式：重复谓语部分的肯定和否定形式 用法：用这一对反义词表示状况的一种反复。','形式：重复谓语部分的肯定和否定形式 用法：用这一对反义词表示状况的一种反复。',NULL,15),
('9937a668-2afa-43cf-9050-86d66553e173','～かったり～かったりです','～かったり～かったりです','N4','～かったり～かったりです','形1かった　形1かった+ り＋です 用法：表示状态或者状况有多种可能。','形1かった　形1かった+ り＋です 用法：表示状态或者状况有多种可能。',NULL,16),
('c0cbac43-9c0e-4266-b9e9-81529b6793a2','～かどうか～','～かどうか～','N4','～かどうか～','一般疑问句 → [小句] 简体 ＋ か　どうか 注意：二类形／名（去掉だ）＋ か　どうか','一般疑问句 → [小句] 简体 ＋ か　どうか 注意：二类形／名（去掉だ）＋ か　どうか',NULL,17),
('4c1682ca-6ab2-4cbf-83b7-48e5b1f3672e','～かな','～かな','N4','～かな','放在简体形疑问小句的结尾。用于自言自语。存在听话人的场合下，用于向对方传达一种不太有把握的信息或寻求确认。','放在简体形疑问小句的结尾。用于自言自语。存在听话人的场合下，用于向对方传达一种不太有把握的信息或寻求确认。',NULL,18),
('74c6618b-36ec-4f1d-9f81-729b034f4d33','～から～ [原因、理由]','～から～ [原因、理由]','N5','～から～ [原因、理由]','[敬体／简体小句（原因）]＋から、……[敬体／简体小句]。から[接续助词]：接在表示理由、原因的小句的句尾，“因为……”。','[敬体／简体小句（原因）]＋から、……[敬体／简体小句]。から[接续助词]：接在表示理由、原因的小句的句尾，“因为……”。',NULL,19),
('041234d4-7d8d-4547-accc-dbc09cd6718a','～から～','～から～','N5','～から～','名[场所]から[动] ～から：空间的起点','名[场所]から[动] ～から：空间的起点',NULL,20),
('71a93c5c-e144-4659-a5d5-220c3d7ecdfa','～から～まで','～から～まで','N5','～から～まで','名[时间]から名[时间]まで 起点→终点','名[时间]から名[时间]まで 起点→终点',NULL,21),
