('70af0914-1a13-451f-a2f5-63b50d4f9da4','二类形容词谓语形式的简体形','二类形容词谓语形式的简体形','N4','二类形容词谓语形式的简体形','だ／ではない／だった／ではなかった','だ／ではない／だった／ではなかった',NULL,140),
('85d25fdf-6edf-4683-beb6-481a8e9bc82d','名词谓语形式的简体形','名词谓语形式的简体形','N4','名词谓语形式的简体形','だ／ではない／だった／ではなかった','だ／ではない／だった／ではなかった',NULL,141),
('4a5ca5f6-54d1-44f3-94d8-a29473cc1350','~間/間に','~間/間に','N3','~間/間に','[名＋]の／[动(简体形)]＋間：表示在某行为或事态持续的时间段； \\n[名＋]の／[动(简体形)]＋間に：表示某行为或事态发生或完成的时间范围。','[名＋]の／[动(简体形)]＋間：表示在某行为或事态持续的时间段； \\n[名＋]の／[动(简体形)]＋間に：表示某行为或事态发生或完成的时间范围。',NULL,142),
('6403c630-7625-498a-b5df-51135b8582ed','お/ご~ください','お/ご~ください','N3','お/ご~ください','“～てください”的敬语形式 \\nお＋[动1]／动2连用形]＋ください \\nご＋[动3的汉字部分]＋ください \\n“お入りください”比“入ってください”礼貌程度高。 \\n连用形只有一个音节的动词不能用于这种形式。','“～てください”的敬语形式 \\nお＋[动1]／动2连用形]＋ください \\nご＋[动3的汉字部分]＋ください \\n“お入りください”比“入ってください”礼貌程度高。 \\n连用形只有一个音节的动词不能用于这种形式。',NULL,143),
('f26e97e7-d3d9-4511-8df5-3b7419e56a4c','お/ご~します','お/ご~します','N3','お/ご~します','お＋[动1]／[动2连用形]＋する　 \\nご＋[动3的汉字部分]+する \\n连用形只有一个音节的动词不能用于这种形式。','お＋[动1]／[动2连用形]＋する　 \\nご＋[动3的汉字部分]+する \\n连用形只有一个音节的动词不能用于这种形式。',NULL,144),
('036712a1-60bc-4e3d-a065-0595539fec4d','お/ご~になります','お/ご~になります','N3','お/ご~になります','お＋[动1／动2连用形]＋になる\\nご＋[动3的汉字部分]+になる  \\n连用形只有一个音节的动词不能用于这种形式。','お＋[动1／动2连用形]＋になる\\nご＋[动3的汉字部分]+になる  \\n连用形只有一个音节的动词不能用于这种形式。',NULL,145),
('29120a21-e4f1-4786-8d61-4b0206aa30b3','~終わります','~終わります','N3','~終わります','[动(连用形)]終わります：表示动作或行为的结束。注意：用于具有一定量的行为、动作。','[动(连用形)]終わります：表示动作或行为的结束。注意：用于具有一定量的行为、动作。',NULL,146),
('f5c050d0-8e27-4914-aee9-c0e1ad82165a','<~が~> ~は/が~','<~が~> ~は/が~','N4','<~が~> ~は/が~','[小句(动词简体形)]+[名]は[名]／[形]です 动词小句简体形+名，形1简体形+名，（形2→词干＋な）+名，（名1＋が＋名2＋の）＋名','[小句(动词简体形)]+[名]は[名]／[形]です 动词小句简体形+名，形1简体形+名，（形2→词干＋な）+名，（名1＋が＋名2＋の）＋名',NULL,147),
('a1e87f19-6094-4c6d-a59a-6372517980ce','~かしら','~かしら','N3','~かしら','和“かな”语义相近，用于简体句句尾，多为女性使用。 \\n1) 没有听话人在场，一般为吐露内心疑问的自言自语。 \\n2) 有听话人在场，向对方发问。','和“かな”语义相近，用于简体句句尾，多为女性使用。 \\n1) 没有听话人在场，一般为吐露内心疑问的自言自语。 \\n2) 有听话人在场，向对方发问。',NULL,148),
('0102acd2-1b76-4d5c-b60e-c62a30f549ec','~かもしれません','~かもしれません','N3','~かもしれません','[小句（简体形）]＋かもしれません 表示推测，其可能性低于“でしょう”   其简体形是“～かもしれない”。','[小句（简体形）]＋かもしれません 表示推测，其可能性低于“でしょう”   其简体形是“～かもしれない”。',NULL,149),
('382c8925-e83d-4f24-9109-7e8c3d5704c8','~ことがあります','~ことがあります','N3','~ことがあります','[动(基本形／ない形)]+ことがあります \\n1) [动(基本形)]+ことがあります：有时会发生某情况 \\n2) [动(ない形)]+ことがあります：有时不做某事 \\n否定形式不是“～ことがありません”','[动(基本形／ない形)]+ことがあります \\n1) [动(基本形)]+ことがあります：有时会发生某情况 \\n2) [动(ない形)]+ことがあります：有时不做某事 \\n否定形式不是“～ことがありません”',NULL,150),
('b15b051e-249c-4778-8748-6c2bf18bdbb8','~ことにします/ことにしました','~ことにします/ことにしました','N3','~ことにします/ことにしました','“我决定……” [动(基本形／ない形)]ことにします／ことにしました 表示说话人自己决定实施某行为时。\\n～ことにします：当场下的决心\\n～ことにしました：已经下定的决心','“我决定……” [动(基本形／ない形)]ことにします／ことにしました 表示说话人自己决定实施某行为时。\\n～ことにします：当场下的决心\\n～ことにしました：已经下定的决心',NULL,151),
('26bccfde-2dfa-462f-b120-152db251e28a','~ことになりました','~ことになりました','N3','~ことになりました','[动(基本形／ない形)]ことになりました 表示由于某种外在的原因，导致某事定下来。\\n为了淡化个人意志，用“ことになります”表达个人的决定。','[动(基本形／ない形)]ことになりました 表示由于某种外在的原因，导致某事定下来。\\n为了淡化个人意志，用“ことになります”表达个人的决定。',NULL,152),
('c93cd55d-ef7c-4a7f-ade1-6b2d4833fd14','~させていただきます','~させていただきます','N3','~させていただきます','用于礼貌地表达自己的动作。礼貌程度高于“お／ご～します”。','用于礼貌地表达自己的动作。礼貌程度高于“お／ご～します”。',NULL,153),
('9344c66f-441b-4732-97a9-4aa4fdd16cbb','~させてください','~させてください','N3','~させてください','动（さ）せてください：请求别人允许自己做某事。 \\n提示：一般说话人不出现在句子中。','动（さ）せてください：请求别人允许自己做某事。 \\n提示：一般说话人不出现在句子中。',NULL,154),
('8273ec78-f826-4553-b6f3-85bcdb9c1881','~し，~し','~し，~し','N3','~し，~し','[小句1]し、[小句2]し、[小句3]　[罗列并列事项][罗列原因]小句1、2的主语“が”多用“も”替换。\\n“し”前面可以是简体形/敬体形。表示理由时，后一个“し”可换成“から”，意思不变。“し”也可以单独使用；单独使用表示理由时，暗示还有其他的理由。','[小句1]し、[小句2]し、[小句3]　[罗列并列事项][罗列原因]小句1、2的主语“が”多用“も”替换。\\n“し”前面可以是简体形/敬体形。表示理由时，后一个“し”可换成“から”，意思不变。“し”也可以单独使用；单独使用表示理由时，暗示还有其他的理由。',NULL,155),
('5588a7ef-b8eb-4608-8f4b-f830223c9837','~しか~(否定)','~しか~(否定)','N3','~しか~(否定)','“只有……”，[名]しか＋否定形式　表示限定。\\n～しか～ない：带有主观感情色彩。','“只有……”，[名]しか＋否定形式　表示限定。\\n～しか～ない：带有主观感情色彩。',NULL,156),
('77a7fe59-d2f4-479e-b3e2-56e82b17ef0a','~過ぎます','~過ぎます','N3','~過ぎます','[动词连用形]/[形1(去掉词尾い)]/[形2词干]+過ぎます：表示超过了正常的量或程度。\\n“～過ぎます”的活用与动2相同。','[动词连用形]/[形1(去掉词尾い)]/[形2词干]+過ぎます：表示超过了正常的量或程度。\\n“～過ぎます”的活用与动2相同。',NULL,157),
('4623e402-ea5a-40d1-b834-7dcf431c13b9','~そうです [传闻]','~そうです [传闻]','N3','~そうです [传闻]','[小句(简体形)]そうです　[传闻] “～そうです”没有过去、否定和疑问的形式。\\n表示消息来源时用“～によると”','[小句(简体形)]そうです　[传闻] “～そうです”没有过去、否定和疑问的形式。\\n表示消息来源时用“～によると”',NULL,158),
('44a1eb41-e161-488d-94b8-12cfdb678b86','~そうです [样态] [推测]','~そうです [样态] [推测]','N3','~そうです [样态] [推测]','[动/形]そうです \\n接续形式：动词连用形/形1去“い”/形2词干＋そうです \\n1)“～そうです”前接形容词时，通常表示“样态”，即根据某对象的外观印象，推测其性质。 \\n2)“～そうです”前接表示活动或变化的动词时，通常表示某事发生前的征兆，即推测某事会发生。 \\n特例：なさそうです/よさそうです \\n否定形式：动 + そう + にも／に／も + ありません; 形1/形2 + そうではありません','[动/形]そうです \\n接续形式：动词连用形/形1去“い”/形2词干＋そうです \\n1)“～そうです”前接形容词时，通常表示“样态”，即根据某对象的外观印象，推测其性质。 \\n2)“～そうです”前接表示活动或变化的动词时，通常表示某事发生前的征兆，即推测某事会发生。 \\n特例：なさそうです/よさそうです \\n否定形式：动 + そう + にも／に／も + ありません; 形1/形2 + そうではありません',NULL,159),
('4ecac854-4f9e-477e-8aac-9eff22c7ceb7','~だけ','~だけ','N3','~だけ','“这就是全部，不再有其他”，[名]だけ 表示客观的限定。 \\n接续：名词／数量词+だけ','“这就是全部，不再有其他”，[名]だけ 表示客观的限定。 \\n接续：名词／数量词+だけ',NULL,160),
('5c9b45b7-a131-4b15-b610-1f2e6f20ac3e','~たところです','~たところです','N3','~たところです','[动]たところです：表示动作或事件刚刚结束（处于“刚刚结束”的阶段）。','[动]たところです：表示动作或事件刚刚结束（处于“刚刚结束”的阶段）。',NULL,161),
('a9aa8928-6955-41cc-89db-292748d06d9b','~たばかりです','~たばかりです','N3','~たばかりです','[动]たばかりです：表示动作或事情刚刚结束。相比～たところです可用于动作结束后经过了较长一段时间的事态','[动]たばかりです：表示动作或事情刚刚结束。相比～たところです可用于动作结束后经过了较长一段时间的事态',NULL,162),
('3e9280e1-87b8-43d9-aff3-2790443ec5e9','~ために，~ [目的]','~ために，~ [目的]','N3','~ために，~ [目的]','([小句1(基本形)]/[名]＋の)＋ために、[小句2] 表示目的，前后两个小句的主语相同。','([小句1(基本形)]/[名]＋の)＋ために、[小句2] 表示目的，前后两个小句的主语相同。',NULL,163),
('06837375-3df1-47bc-986c-f035a35fc6df','~ために，~ [原因、理由]','~ために，~ [原因、理由]','N3','~ために，~ [原因、理由]','([小句1(简体形)]/[名]＋の/[形2]＋な)＋ために、[小句2] \\n1) 多用于书面语或比较郑重的场合； \\n2) 小句1多为非意志性的事态或状态。','([小句1(简体形)]/[名]＋の/[形2]＋な)＋ために、[小句2] \\n1) 多用于书面语或比较郑重的场合； \\n2) 小句1多为非意志性的事态或状态。',NULL,164),
('abbc34fe-b056-4f19-a13f-60830817f9fd','~たら，~','~たら，~','N3','~たら，~','[小句1]たら、[小句2]　用于表示假定条件。 \\n用法1：假定条件（在不知道前项是否成立的情况下，假设其成立），“要是……的话……就” \\n用法2：既定条件（在知道前项肯定成立的情况下）“在……之后” \\n接续： “た”→“たら” \\n动词否定：未然形+否定+たらー＞なかったら\\n“～ます”＋“～たら”→“~ましたら” \\n“～です”＋“～たら”→“~でしたら” \\n一类形容词后续“～たら”时，不用敬体形。\\n过去否定形式～で(は)なかった->でなかったら','[小句1]たら、[小句2]　用于表示假定条件。 \\n用法1：假定条件（在不知道前项是否成立的情况下，假设其成立），“要是……的话……就” \\n用法2：既定条件（在知道前项肯定成立的情况下）“在……之后” \\n接续： “た”→“たら” \\n动词否定：未然形+否定+たらー＞なかったら\\n“～ます”＋“～たら”→“~ましたら” \\n“～です”＋“～たら”→“~でしたら” \\n一类形容词后续“～たら”时，不用敬体形。\\n过去否定形式～で(は)なかった->でなかったら',NULL,165),
('20f86be3-e0d5-4495-86be-b8de87c837a2','~ちゃった','~ちゃった','N3','~ちゃった','为33课～てしまった的口语形式，语义基本相同，但令人不愉快的语气更弱。','为33课～てしまった的口语形式，语义基本相同，但令人不愉快的语气更弱。',NULL,166),
('6027e3ea-c7b6-4e65-bb3b-e6bbdedfd8d5','~続けます','~続けます','N3','~続けます','[动(连用形)]続けます：表示动作或状态不间断的持续。\\n“降ります”后面不能接“続けます”而须后接“続きます”。','[动(连用形)]続けます：表示动作或状态不间断的持续。\\n“降ります”后面不能接“続けます”而须后接“続きます”。',NULL,167),
('a988c936-1c1e-4385-80fe-3a608cf89f06','~つもりです','~つもりです','N3','~つもりです','[动(基本形／ない形)]つもりです 表示说话之前已经形成的意志、打算。 \\n～ないつもりです：我打算不做…… \\n～つもりはないです／つもりはありません：我不打算做……，是强烈的拒绝语气。','[动(基本形／ない形)]つもりです 表示说话之前已经形成的意志、打算。 \\n～ないつもりです：我打算不做…… \\n～つもりはないです／つもりはありません：我不打算做……，是强烈的拒绝语气。',NULL,168),
('a9d57992-3391-4f0d-8e25-e248d610441f','~て/~ないで','~て/~ないで','N3','~て/~ないで','[动]て／[动]ないで 表示祈使或轻微命令，用于关系亲密的人之间。','[动]て／[动]ないで 表示祈使或轻微命令，用于关系亲密的人之间。',NULL,169),
('f932b614-a5d1-400d-9937-963cdc1e2b1b','~て~/~ないで~','~て~/~ないで~','N3','~て~/~ないで~','[小句1]て／ないで＋[小句2]　　[伴随状态] 表示进行小句2的动作主体处于小句1的状态 “～ないで”也可以说成“～ずに”，“～ずに”多用于书面语。','[小句1]て／ないで＋[小句2]　　[伴随状态] 表示进行小句2的动作主体处于小句1的状态 “～ないで”也可以说成“～ずに”，“～ずに”多用于书面语。',NULL,170),
('aa454764-be5f-447c-b774-2ae7a2372e89','~て，~/~で，~ [原因、理由]','~て，~/~で，~ [原因、理由]','N3','~て，~/~で，~ [原因、理由]','[小句1(动／形1)]て/[小句1(名／形2)]で、[小句2]　[原因、理由] 注意：小句2不可以是祈使句。 否定：ない→なくて','[小句1(动／形1)]て/[小句1(名／形2)]で、[小句2]　[原因、理由] 注意：小句2不可以是祈使句。 否定：ない→なくて',NULL,171),
('40010baf-08f8-469b-8aba-26d20c38ae34','~で [原因、理由]','~で [原因、理由]','N3','~で [原因、理由]','名＋で [原因、理由]','名＋で [原因、理由]',NULL,172),
('51d067ac-5059-4526-8daa-3e4a48b39d5c','で/へ/から/まで/と+の','で/へ/から/まで/と+の','N3','で/へ/から/まで/と+の','で／へ／から／まで／と／ばかり等助词可以加 の 构成定语，修饰名词。 “に”不能后续“の”，而要改成“への”的形式。','で／へ／から／まで／と／ばかり等助词可以加 の 构成定语，修饰名词。 “に”不能后续“の”，而要改成“への”的形式。',NULL,173),
('66617c25-1b4d-444b-a7e0-1f3f0c8214a1','~てあげます','~てあげます','N3','~てあげます','[动]てあげます Aは／がBに～てあげる 　“A为B做某事” A：行为主体（提供帮助的人） B：受益人 ~：A的行为','[动]てあげます Aは／がBに～てあげる 　“A为B做某事” A：行为主体（提供帮助的人） B：受益人 ~：A的行为',NULL,174),
('f950591e-93a7-4659-8c19-64c91ca521ae','~てあります','~てあります','N3','~てあります','[他动]てある 表示有意进行的动作结果的存续状态。按照动1活用。 不出现意志、请求、祈使、命令等形式。','[他动]てある 表示有意进行的动作结果的存续状态。按照动1活用。 不出现意志、请求、祈使、命令等形式。',NULL,175),
('4eb6cdcc-0557-4c87-82bd-ce057b13a9e8','~である','~である','N3','~である','“です”的书面语简体形式。','“です”的书面语简体形式。',NULL,176),
('c9267add-abd0-427f-aeef-70adbcd7ab62','~ていきます/きました [持续] [变化]','~ていきます/きました [持续] [变化]','N3','~ていきます/きました [持续] [变化]','用法：1) 空间移动，2) 时间移动 \\nてくる：由基准时间点之前向基准时间点推移、变化。“由过去到现在”。 \\nていく：由基准时间点向基准时间点之后推移、变化。“由现在到将来”。','用法：1) 空间移动，2) 时间移动 \\nてくる：由基准时间点之前向基准时间点推移、变化。“由过去到现在”。 \\nていく：由基准时间点向基准时间点之后推移、变化。“由现在到将来”。',NULL,177),
('8b474c20-ed33-4085-ac3e-73cbd3cc3037','~ていきます/きます','~ていきます/きます','N3','~ていきます/きます','[动]ていきます／きます　\\n实义动词，表示独立的动作。\\n1) て前接表示独立动作的动词: 食べる、買う、見る、休む。此时，て形表示两个相继发生的动作。\\n2) て前面的动词表示动作主体的状况: 着る、穿く、かける、持つ、連れる。此时，て形表示伴随状态。\\n补助动词，不表示独立的动作。\\n1) 表示以说话人为起点，空间上的移动方向。前接表示移动的动词: 帰る、歩く、走る、泳ぐ、飛ぶ、乗る \\n~ていく：由近及远，~てくる：由远及近','[动]ていきます／きます　\\n实义动词，表示独立的动作。\\n1) て前接表示独立动作的动词: 食べる、買う、見る、休む。此时，て形表示两个相继发生的动作。\\n2) て前面的动词表示动作主体的状况: 着る、穿く、かける、持つ、連れる。此时，て形表示伴随状态。\\n补助动词，不表示独立的动作。\\n1) 表示以说话人为起点，空间上的移动方向。前接表示移动的动词: 帰る、歩く、走る、泳ぐ、飛ぶ、乗る \\n~ていく：由近及远，~てくる：由远及近',NULL,178),
('5190ceac-40e0-4ff7-9891-6a46914abc77','~ていただきます','~ていただきます','N3','~ていただきます','“もらいます”的自谦语形式','“もらいます”的自谦语形式',NULL,179),
('7279e456-0540-4d44-9de6-117e3ae50876','~ていただけますか [请求]','~ていただけますか [请求]','N3','~ていただけますか [请求]','用于礼貌地请求别人为自己做某事。 “~ていただけませんか”比“~ていただけますか”礼貌程度高。','用于礼貌地请求别人为自己做某事。 “~ていただけませんか”比“~ていただけますか”礼貌程度高。',NULL,180),
('d602fe93-f1ba-4c0f-b643-92ff286dfe12','~ています [反复] [习惯]','~ています [反复] [习惯]','N3','~ています [反复] [习惯]','[动]ています： [反复][习惯] 表示习惯时，“～ています”“～ます”都可以使用， 但句中出现表示时间起点的形式时，不用“～ます”。','[动]ています： [反复][习惯] 表示习惯时，“～ています”“～ます”都可以使用， 但句中出现表示时间起点的形式时，不用“～ます”。',NULL,181),
('71097613-548c-4b44-b9b7-d20188b2c3c8','~ています [结果状态]','~ています [结果状态]','N3','~ています [结果状态]','[自动]ています 1）自动词表示动作，则“～ています”表示该动作正在进行。\\n2）自动词表示变化，“～ています”表示结果的存续。','[自动]ています 1）自动词表示动作，则“～ています”表示该动作正在进行。\\n2）自动词表示变化，“～ています”表示结果的存续。',NULL,182),
('7ace149c-fac3-493e-834d-13c1a9149088','~ていらっしゃいます','~ていらっしゃいます','N3','~ていらっしゃいます','“～ています／～ていきます／～てきます”的尊他语。','“～ています／～ていきます／～てきます”的尊他语。',NULL,183),
('c5f38bf1-03fe-40e7-8a44-dbe67ab80a63','~ているところです','~ているところです','N3','~ているところです','[动]ているところです：表示正在做的过程中（处于“正进行中”的阶段）。','[动]ているところです：表示正在做的过程中（处于“正进行中”的阶段）。',NULL,184),
('87d849ec-46b4-4c15-a0e5-5831565ebf35','~ておきます','~ておきます','N3','~ておきます','[动]ておく 在随便的口语中有时会缩略成：とく，均按照动1活用 \\n1) 为了某个目的而事先做某事。[准备] \\n2) 为了某个目的而做某事，并使其结果或效果留存下来。[留存]','[动]ておく 在随便的口语中有时会缩略成：とく，均按照动1活用 \\n1) 为了某个目的而事先做某事。[准备] \\n2) 为了某个目的而做某事，并使其结果或效果留存下来。[留存]',NULL,185),
('e61a2445-a7dc-49ef-a6ad-90013bae1cc6','~ております','~ております','N3','~ております','“ています”的自谦语形式。','“ています”的自谦语形式。',NULL,186),
('166e7c04-75a3-42fe-9179-18b1949c75cf','~てきます','~てきます','N3','~てきます','在口语中，表示去别处做某事后再回到原处， “去去就来”。','在口语中，表示去别处做某事后再回到原处， “去去就来”。',NULL,187),
('814f132f-cf49-40b6-905f-14920b097f9b','~てきました [出现]','~てきました [出现]','N3','~てきました [出现]','表示某种状态的开始或出现，只限于前接非意志性动词。','表示某种状态的开始或出现，只限于前接非意志性动词。',NULL,188),
('57a61fc8-da96-4f1a-a8bf-702d9127debd','~てくださいます','~てくださいます','N3','~てくださいます','“～てくれる”的尊他语。','“～てくれる”的尊他语。',NULL,189),
('049b1e3a-f013-4910-8c79-06935acb490d','~てくれます','~てくれます','N3','~てくれます','[动]てくれます Aは／がBに～てくれる：表示“他人（A）为我或我方人员（B）做某事” A：提供帮助的人（动作主体） B：受益人（我或我方人员） ~：A的行为','[动]てくれます Aは／がBに～てくれる：表示“他人（A）为我或我方人员（B）做某事” A：提供帮助的人（动作主体） B：受益人（我或我方人员） ~：A的行为',NULL,190),
('b297fd10-99ba-43a5-b345-87e185ab4a89','~でございます','~でございます','N3','~でございます','ございます：“あります”更为礼貌的说法。 でございます：“です”更为礼貌的说法。','ございます：“あります”更为礼貌的说法。 でございます：“です”更为礼貌的说法。',NULL,191),
('548a3e12-8862-4dfb-8d9b-404310606dbb','~差し上げます','~差し上げます','N3','~差し上げます','“あげる”的自谦语形式','“あげる”的自谦语形式',NULL,192),
('0dd301b7-e543-45f2-873c-92f71b026a56','~てしまいます','~てしまいます','N3','~てしまいます','[动]てしまいます \\n1) 该动作所产生的结果是令人不愉快的事情。 \\n2) 完成。（这种情况下，该动作一般是有意进行的）','[动]てしまいます \\n1) 该动作所产生的结果是令人不愉快的事情。 \\n2) 完成。（这种情况下，该动作一般是有意进行的）',NULL,193),
('d3ad5a83-7984-4f20-ae74-b79a3e3dd814','~でしょう [推测]','~でしょう [推测]','N3','~でしょう [推测]','[小句（简体形）]＋でしょう。  “～でしょう” 表示推测。“大概，也许。”','[小句（简体形）]＋でしょう。  “～でしょう” 表示推测。“大概，也许。”',NULL,194),
('88b8b57c-a0d9-4948-933f-4056ef6541d8','~でしょう? [确认]','~でしょう? [确认]','N3','~でしょう? [确认]','[小句(简体形)]でしょう？ ①确认对方比自己更为熟悉的事情，读升调； ②当对方和自己意见不同，或叮问对方，读降调。','[小句(简体形)]でしょう？ ①确认对方比自己更为熟悉的事情，读升调； ②当对方和自己意见不同，或叮问对方，读降调。',NULL,195),
('9decd693-66ed-4027-afb5-55d2650d9155','~でしょうか','~でしょうか','N3','~でしょうか','[小句(简体形式)]でしょうか：礼貌地对听话人表示疑问 接续： 1) 动／形1：简体＋でしょうか 2) 名／形2：简体去掉だ+でしょうか','[小句(简体形式)]でしょうか：礼貌地对听话人表示疑问 接续： 1) 动／形1：简体＋でしょうか 2) 名／形2：简体去掉だ+でしょうか',NULL,196),
('8858ed51-c299-4446-9196-98ee7b9f50b8','~ですもの/~だもん','~ですもの/~だもん','N3','~ですもの/~だもん','口语中附于句尾，用于述说理由，带有抗议、不满、诉说、感叹、辩解等语气。 \\n“～ですもの”的简体是“~だもの”，且于关系亲密的人之间。 \\n“～だもの”→“～だもん”更随便，带有一种撒娇的语感，多为女性和孩子所用','口语中附于句尾，用于述说理由，带有抗议、不满、诉说、感叹、辩解等语气。 \\n“～ですもの”的简体是“~だもの”，且于关系亲密的人之间。 \\n“～だもの”→“～だもん”更随便，带有一种撒娇的语感，多为女性和孩子所用',NULL,197),
('b7db317b-7809-4636-8684-e827e2161d4d','~ではありませんか','~ではありませんか','N3','~ではありませんか','～もしかしたら 口语形式，一般与“~かもしれません”“～ではありませんか”等呼应使用，用于可能性较低的场合，表示“也许”“莫非”等意。','～もしかしたら 口语形式，一般与“~かもしれません”“～ではありませんか”等呼应使用，用于可能性较低的场合，表示“也许”“莫非”等意。',NULL,198),
('ca7415f9-f878-4bbb-91df-c6f6d50ffc85','~てほしい','~てほしい','N3','~てほしい','(～に) [动]てほしい 表示对他人的愿望，希望他人做某事 \\n当动作主体是自然、客观的事物时，主体后用助词“が” \\n直接提出要求的表达方式，礼貌程度较低，不能直接对长辈和上级使用。','(～に) [动]てほしい 表示对他人的愿望，希望他人做某事 \\n当动作主体是自然、客观的事物时，主体后用助词“が” \\n直接提出要求的表达方式，礼貌程度较低，不能直接对长辈和上级使用。',NULL,199),
('0ab1ff76-c042-423a-885d-58020b1cf271','~てみます','~てみます','N3','~てみます','[动]てみる 表示尝试做某事。按照动2活用。','[动]てみる 表示尝试做某事。按照动2活用。',NULL,200);

INSERT IGNORE INTO grammar_lessons
  (id,title,title_zh,jlpt_level,pattern,explanation,explanation_zh,usage_notes,order_index)
VALUES
('642ee840-60c1-4079-a77e-e8eac9c04896','~ても，~','~ても，~','N3','~ても，~','“即使……也……，尽管……还是……”。[小句1]ても、[小句2]　表示逆接关系 \\n用于“小句1”成立时“小句2”理应成立但事实上却没有成立。\\n接续：动：“て／で”→“ても／でも” \\n　　　形1：“て”→“ても” \\n　　　形2／名词：“で”→“でも”','“即使……也……，尽管……还是……”。[小句1]ても、[小句2]　表示逆接关系 \\n用于“小句1”成立时“小句2”理应成立但事实上却没有成立。\\n接续：动：“て／で”→“ても／でも” \\n　　　形1：“て”→“ても” \\n　　　形2／名词：“で”→“でも”',NULL,201),
('2c83d1f2-b1fc-4aeb-95a3-696066aefe56','~でも [提示极端的例子]','~でも [提示极端的例子]','N3','~でも [提示极端的例子]','[名]+でも：提示极端的例子，“就连……”','[名]+でも：提示极端的例子，“就连……”',NULL,202),
('ab7ea08f-7691-48ac-b025-bc76fc0cda6f','~でも [示例]','~でも [示例]','N3','~でも [示例]','[名]でも　[示例] 用于举出几个选项中有代表性的一项。','[名]でも　[示例] 用于举出几个选项中有代表性的一项。',NULL,203),
('b15c13ca-5849-4d9d-b381-0bd443e5c065','~てもらいます','~てもらいます','N3','~てもらいます','[动]てもらいます “A从B处得到某项帮助/A由于B的行为而得到某种恩惠” A：受益人 B：行为主体（提供帮助的人） ~：B的行为','[动]てもらいます “A从B处得到某项帮助/A由于B的行为而得到某种恩惠” A：受益人 B：行为主体（提供帮助的人） ~：B的行为',NULL,204),
('a01f2471-e792-4d01-8d59-939a3bf239c4','~と，~','~と，~','N3','~と，~','[小句1(动词基本形／ない形)]と、小句2：“一……就……” 1) 表示恒常性状态、真理、反复状态、习惯； 2) 表示由于某种行为而发现了新的情况。 “～と”的后面不会出现表示意志，希望，命令，请求等表达方式。','[小句1(动词基本形／ない形)]と、小句2：“一……就……” 1) 表示恒常性状态、真理、反复状态、习惯； 2) 表示由于某种行为而发现了新的情况。 “～と”的后面不会出现表示意志，希望，命令，请求等表达方式。',NULL,205),
('e7cc2d18-1718-408b-8230-974edffe591b','~と会います','~と会います','N3','~と会います','[名]と会います “～に”：表示单向性的行为对象 “～と”：表示双向性的行为对象','[名]と会います “～に”：表示单向性的行为对象 “～と”：表示双向性的行为对象',NULL,206),
('43962ab1-6f18-4ba7-a1fb-22aa93f9e473','~という~','~という~','N3','~という~','[名1]＋という＋[名2]：表示称谓，“叫做……”','[名1]＋という＋[名2]：表示称谓，“叫做……”',NULL,207),
('a4038fb2-dc32-4853-8750-e7dc33bf0bf0','~と思います','~と思います','N3','~と思います','[动(意志形)]＋と思います 用法：将自己要做某事的意志告诉听话人。1) 是表示个人意志的表达方式，通常只能用于第一人称。 2) 问句可用于第二人称，用于直接询问对方的意志。','[动(意志形)]＋と思います 用法：将自己要做某事的意志告诉听话人。1) 是表示个人意志的表达方式，通常只能用于第一人称。 2) 问句可用于第二人称，用于直接询问对方的意志。',NULL,208),
('e376d1f8-f2cc-43b3-9585-66737e79ff48','~と思っています','~と思っています','N3','~と思っています','[动(意志形)]+ と思っています 用法：表示某种意志持续了一段时间。可用于第三人称。','[动(意志形)]+ と思っています 用法：表示某种意志持续了一段时间。可用于第三人称。',NULL,209),
('5dbf8155-4687-4c2a-87d8-1706e487e23a','~とか~とか','~とか~とか','N3','~とか~とか','[名1]とか[名2]とか　[小句1]とか[小句2]とか 用于列举同样性质的几个例子。“～とか～”只用于口语','[名1]とか[名2]とか　[小句1]とか[小句2]とか 用于列举同样性质的几个例子。“～とか～”只用于口语',NULL,210),
('755e45e6-2997-4f82-8380-b43df0d8bbb6','~時，~','~時，~','N3','~時，~','小句(简)+時：“……的时候，……” \\n接续：名+の/形1(简)/形2(词干)+な/动(简) +時 \\na.～する（基本形）＋時、…：表示后项动作实现时，前项动作未完成 \\nb.～した（た形）＋時、…：表示后项动作实现时，前项动作已完成','小句(简)+時：“……的时候，……” \\n接续：名+の/形1(简)/形2(词干)+な/动(简) +時 \\na.～する（基本形）＋時、…：表示后项动作实现时，前项动作未完成 \\nb.～した（た形）＋時、…：表示后项动作实现时，前项动作已完成',NULL,211),
('339a34d7-c5b5-4f64-87d5-f1e18f104388','~ところです','~ところです','N3','~ところです','[动(基本形)]ところです：表示动作即将进行（处于“即将做”的阶段）。','[动(基本形)]ところです：表示动作即将进行（处于“即将做”的阶段）。',NULL,212),
('a55c7dba-da7d-4bb6-8515-bf905f3bf99c','~な [禁止]','~な [禁止]','N3','~な [禁止]','[动(基本形)]+な：禁止 放在句尾　用于禁止听话人做某事 其语气的强硬程度与动词命令形相当，较粗鲁。','[动(基本形)]+な：禁止 放在句尾　用于禁止听话人做某事 其语气的强硬程度与动词命令形相当，较粗鲁。',NULL,213),
('a00c0a3d-d359-44e4-85c2-0f6c4d292820','~ないと/~ないといけません','~ないと/~ないといけません','N3','~ないと/~ないといけません','表示必须或义务，“不……不行，不得不……”。 ないと是“~ないといけません／～ないといけない”的省略形式','表示必须或义务，“不……不行，不得不……”。 ないと是“~ないといけません／～ないといけない”的省略形式',NULL,214),
('feedac49-14b8-4b7d-b36a-4e66588c7a94','~ながら','~ながら','N3','~ながら','“一边…一边…” 动＋ながら 接续：连用形＋“ながら”。 后面的动作是主要动作，前面的动作是次要动作。','“一边…一边…” 动＋ながら 接续：连用形＋“ながら”。 后面的动作是主要动作，前面的动作是次要动作。',NULL,215),
('b124ffb5-c15f-4363-a914-13a51311e8f8','~なければ/~なければなりません','~なければ/~なければなりません','N3','~なければ/~なければなりません','“必须……，不得不……” なければ：“～なければなりません／～なければならない”的省略形式','“必须……，不得不……” なければ：“～なければなりません／～なければならない”的省略形式',NULL,216),
('c188a904-e719-4243-9dcb-6310918738be','~なさい','~なさい','N3','~なさい','动词连用形＋“なさい” 多用于长辈对晚辈、老师对学生、上司对下属下命令；语气比命令型客气。','动词连用形＋“なさい” 多用于长辈对晚辈、老师对学生、上司对下属下命令；语气比命令型客气。',NULL,217),
('81037da3-d8b1-4d03-b47f-001d5601daed','~なら，~','~なら，~','N3','~なら，~','[小句1(简体形)]なら、[小句2] \\n根据对方的言谈或现场情况，陈述自己的意见或想法，以及向对方提出请求或忠告 \\n接续：简体形式＋なら; 形2／名词：去掉简体形式中的だ＋なら','[小句1(简体形)]なら、[小句2] \\n根据对方的言谈或现场情况，陈述自己的意见或想法，以及向对方提出请求或忠告 \\n接续：简体形式＋なら; 形2／名词：去掉简体形式中的だ＋なら',NULL,218),
('bfaabd29-283a-47a6-b0b1-f1fcb2cf11ec','~に [用途] [基准]','~に [用途] [基准]','N3','~に [用途] [基准]','[名]に 1) 表示用途时，前面是具体说明用途的名词，后面多是“使う”等动词； \\n2) 表示基准时，前面的名词是基准，后面一般是表示评价的形容词。','[名]に 1) 表示用途时，前面是具体说明用途的名词，后面多是“使う”等动词； \\n2) 表示基准时，前面的名词是基准，后面一般是表示评价的形容词。',NULL,219),
('93d65e49-7cc9-4e9d-a723-d4f1b5a3d3d9','~によると','~によると','N3','~によると','表示消息来源时用“～によると”','表示消息来源时用“～によると”',NULL,220),
('6f6b9e08-e5b9-4401-9aa2-d4316635f49e','~によって','~によって','N3','~によって','[名(事物)]は ~によって[动] (ら)れます。 在事物做主语的被动句里，当动作主体是特定的人时，用“～によって”来表示。','[名(事物)]は ~によって[动] (ら)れます。 在事物做主语的被动句里，当动作主体是特定的人时，用“～によって”来表示。',NULL,221),
('f1d65f0a-6535-423a-b2de-feec7b0b2641','~のが~です','~のが~です','N3','~のが~です','当谓语是表示感情或擅长不擅长的形容词（好きです、嫌いです、苦手です、上手です、下手です）时，主语要用助词“が”来表示。','当谓语是表示感情或擅长不擅长的形容词（好きです、嫌いです、苦手です、上手です、下手です）时，主语要用助词“が”来表示。',NULL,222),
('1af07082-5e84-433a-84b6-d7517c26f973','~のが見えます/~のが聞こえます','~のが見えます/~のが聞こえます','N3','~のが見えます/~のが聞こえます','某种景象映入眼帘/某种声音传入耳朵 [小句(简体形)]+の+が＋見えます／聞こえます \\n小句：形2词干＋な＋の; 形1+の; 形2+な＋の','某种景象映入眼帘/某种声音传入耳朵 [小句(简体形)]+の+が＋見えます／聞こえます \\n小句：形2词干＋な＋の; 形1+の; 形2+な＋の',NULL,223),
('adb91401-6c94-4d83-8f5a-275853b5e298','~のために，~ [目的]','~のために，~ [目的]','N3','~のために，~ [目的]','[名]＋の＋ために、[小句] 表示目的，前后两个小句的主语相同。','[名]＋の＋ために、[小句] 表示目的，前后两个小句的主语相同。',NULL,224),
('b06ce9a5-2a66-44aa-92f0-df9b257d811f','~のために，~ [原因、理由]','~のために，~ [原因、理由]','N3','~のために，~ [原因、理由]','[名]＋の＋ために、[小句2] \\n1) 多用于书面语或比较郑重的场合； \\n2) 小句1多为非意志性的事态或状态。','[名]＋の＋ために、[小句2] \\n1) 多用于书面语或比较郑重的场合； \\n2) 小句1多为非意志性的事态或状态。',NULL,225),
('27d55226-8696-4659-b88a-cb0183280068','~ので，~','~ので，~','N3','~ので，~','[小句1]+ので+[小句2] 用于客观叙述某事的原因、理由。接续：简体／敬体+ので，前接简体较多；动词／形1简体＋ので；名词／形2简体（だ→な）＋ので；','[小句1]+ので+[小句2] 用于客观叙述某事的原因、理由。接续：简体／敬体+ので，前接简体较多；动词／形1简体＋ので；名词／形2简体（だ→な）＋ので；',NULL,226),
('7d9df1a9-068b-491c-adbe-55a480c5cf65','~のではないでしょうか [婉转陈述意见的表达]','~のではないでしょうか [婉转陈述意见的表达]','N3','~のではないでしょうか [婉转陈述意见的表达]','～のではないでしょうか：是婉转陈述意见的表达方式。“不是…吗？”。 \\n否定+疑问，表达的是一种委婉的肯定， 相当于“～と思います”，但更加委婉。 \\n简体形式是：“～んじゃない？”','～のではないでしょうか：是婉转陈述意见的表达方式。“不是…吗？”。 \\n否定+疑问，表达的是一种委婉的肯定， 相当于“～と思います”，但更加委婉。 \\n简体形式是：“～んじゃない？”',NULL,227),
('55fe61c5-cde9-43d1-a414-9c5e6d1ba7b4','~の時，~','~の時，~','N3','~の時，~','“……的时候” 名词＋の＋時','“……的时候” 名词＋の＋時',NULL,228),
('27a5f707-fc6c-4ae5-9b7e-9bd0e2d28365','~のに [用途] [基准]','~のに [用途] [基准]','N3','~のに [用途] [基准]','[动(基本形)]＋の＋に \\n1) 表示用途时，前面是具体说明用途的名词，后面多是“使う”等动词； \\n2) 表示基准时，前面的名词是基准，后面一般是表示评价的形容词。','[动(基本形)]＋の＋に \\n1) 表示用途时，前面是具体说明用途的名词，后面多是“使う”等动词； \\n2) 表示基准时，前面的名词是基准，后面一般是表示评价的形容词。',NULL,229),
('8f1414f3-3b24-4fb5-95d2-7559d8deb7a2','~のに，~','~のに，~','N3','~のに，~','“明明……却，偏偏……”。 [小句1(简体形)]のに、[小句2]　[逆接] \\n逆接：前项与后项是有矛盾的。 表示在小句1的情况下，发生小句2的情况不符合常识常理， \\n接续：[小句(简体形)]＋のに \\n[名词／形2な形]＋のに','“明明……却，偏偏……”。 [小句1(简体形)]のに、[小句2]　[逆接] \\n逆接：前项与后项是有矛盾的。 表示在小句1的情况下，发生小句2的情况不符合常识常理， \\n接续：[小句(简体形)]＋のに \\n[名词／形2な形]＋のに',NULL,230),
('8aaee846-84c8-43f3-8203-43c0f157c7d7','~のは~です','~のは~です','N3','~のは~です','小句（动词简体形）＋の＋は[形]です。动词小句加形式名词“の”使之名词化，表示“做某动作”之意。 以上名词化形式作主语，而谓语是表示性质、状态的形1、形2时，主语用“は”表示。','小句（动词简体形）＋の＋は[形]です。动词小句加形式名词“の”使之名词化，表示“做某动作”之意。 以上名词化形式作主语，而谓语是表示性质、状态的形1、形2时，主语用“は”表示。',NULL,231),
('dc201d43-a29a-4079-a6be-04c23e3670fa','~のまま，~','~のまま，~','N3','~のまま，~','[名]＋のまま、小句 表示将理应改变的某状态保持着去进行另外的动作。','[名]＋のまま、小句 表示将理应改变的某状态保持着去进行另外的动作。',NULL,232),
('152fc94e-2a2f-4bc9-a798-b4b35d0c3757','~のようです [推測]','~のようです [推測]','N3','~のようです [推測]','[名]＋のようです 表示根据说话人感知的某种情况进行推测，“好像，似乎“。','[名]＋のようです 表示根据说话人感知的某种情况进行推测，“好像，似乎“。',NULL,233),
('0f09f859-2828-466e-ac3d-16668094394e','~のような味/においがします','~のような味/においがします','N3','~のような味/においがします','感觉到某种味道或气味，用法中的助词“が”和动词“する”，不能随意换用“を”和“ある”。 \\n还可以是 \\n“味／におい／声／音／感じ”がする \\n“頭痛／寒気／吐き気／眩暈（めまい）”がする','感觉到某种味道或气味，用法中的助词“が”和动词“する”，不能随意换用“を”和“ある”。 \\n还可以是 \\n“味／におい／声／音／感じ”がする \\n“頭痛／寒気／吐き気／眩暈（めまい）”がする',NULL,234),
('faf94a58-563c-4952-a48e-afdde4601cb8','~のを~','~のを~','N3','~のを~','小句（动词简体形）＋の＋を[动]。 这种名词化形式做宾语时，“の”和“こと”可以互换。 表达信息内容时，用“こと”；表示某动作时，用“の”。','小句（动词简体形）＋の＋を[动]。 这种名词化形式做宾语时，“の”和“こと”可以互换。 表达信息内容时，用“こと”；表示某动作时，用“の”。',NULL,235),
('c9bf6b42-ff49-4413-8c25-f55f6ae10092','~ば，~','~ば，~','N3','~ば，~','[小句1]ば、[小句2]：表示小句1是小句2的必要条件。\\n原则上句尾不能使用表示意志、希望、命令、请求的表达方式。不过，如果小句1的谓语为状态性谓语或者前后两个小句的主语不同时，则不受此限制。','[小句1]ば、[小句2]：表示小句1是小句2的必要条件。\\n原则上句尾不能使用表示意志、希望、命令、请求的表达方式。不过，如果小句1的谓语为状态性谓语或者前后两个小句的主语不同时，则不受此限制。',NULL,236),
('28553102-b25d-4945-bfb1-0320e89418b3','~は~という~です','~は~という~です','N3','~は~という~です','[名1]は[名/小句]+という +[名2]です。用于对名词1下定义或做解释。[小句]可以是命令形、简体形、简体形+な等形式。\\n「という」后面的[名2]多为“意味（意思）”，也可是其它名词','[名1]は[名/小句]+という +[名2]です。用于对名词1下定义或做解释。[小句]可以是命令形、简体形、简体形+な等形式。\\n「という」后面的[名2]多为“意味（意思）”，也可是其它名词',NULL,237),
('8bb73b3a-cd70-4162-bd25-160e727da60c','~は~に~られます','~は~に~られます','N3','~は~に~られます','受害被动句 [名1]は[名2]に[动] (ら)れます。 动作主体的动作并不直接作用于主语，但主语由于此动作而间接承受了某不良影响。原主动句中不存在的名词或名词短语，成为被动句的主语。','受害被动句 [名1]は[名2]に[动] (ら)れます。 动作主体的动作并不直接作用于主语，但主语由于此动作而间接承受了某不良影响。原主动句中不存在的名词或名词短语，成为被动句的主语。',NULL,238),
('07d4f90e-9477-41aa-90ad-cd42633cf793','~は~に~を~させます','~は~に~を~させます','N3','~は~に~を~させます','他动词的使役句 [名1(使役主体)]は[名2(动作主体)]に[名3(动作的宾语/直接作用点)]を[他动]（さ）せます。','他动词的使役句 [名1(使役主体)]は[名2(动作主体)]に[名3(动作的宾语/直接作用点)]を[他动]（さ）せます。',NULL,239),
('d88e3449-e2cf-4885-a848-8b8e14f68c28','~は~に~を~られます','~は~に~を~られます','N3','~は~に~を~られます','持有者被动句 [名1 物主]は[名2 动作施加者]に[名3 名1的所有物]を[动] (ら)れます。 句型表示该事物[名3]的持有者[名1]，由于动作主体[名2]的某动作，而遭受了某种麻烦或损失。','持有者被动句 [名1 物主]は[名2 动作施加者]に[名3 名1的所有物]を[动] (ら)れます。 句型表示该事物[名3]的持有者[名1]，由于动作主体[名2]的某动作，而遭受了某种麻烦或损失。',NULL,240),
('1dda9046-5872-4d7a-9d22-b0cce144de7f','~は~に~をくれます','~は~に~をくれます','N3','~は~に~をくれます','AはBに～をくれます。“A给B~”（B是“我”或“我方人员”） 物/所有权“由外向内”移动  别人给说话人(一方)的人某物','AはBに～をくれます。“A给B~”（B是“我”或“我方人员”） 物/所有权“由外向内”移动  别人给说话人(一方)的人某物',NULL,241),
('81626b60-feef-43ff-a525-dc5d4c62d7f4','~ば~ほど','~ば~ほど','N3','~ば~ほど','“越……越……” 某性质的程度与其相关的动作、性质，成正比例关系。\\n有五种接续方式','“越……越……” 某性质的程度与其相关的动作、性质，成正比例关系。\\n有五种接续方式',NULL,242),
('d57c6665-b9d5-46d1-8723-92c230bcf5eb','~が/は~られます','~が/は~られます','N3','~が/は~られます','事物做主语的被动句 [名(事物)]が／は[动] (ら)れます。 此句型中，动作主体一般是不确定的人的群体，因此一般在句子中不出现。','事物做主语的被动句 [名(事物)]が／は[动] (ら)れます。 此句型中，动作主体一般是不确定的人的群体，因此一般在句子中不出现。',NULL,243),
('abc75f93-27e3-4bb5-afca-b040b667e565','~は~を~させます','~は~を~させます','N3','~は~を~させます','自动词的使役句 [名1(使役主体)]は[名2(动作主体/被使役者)]を[自动]（さ）せます。','自动词的使役句 [名1(使役主体)]は[名2(动作主体/被使役者)]を[自动]（さ）せます。',NULL,244),
('c4ba217e-8acc-47e1-ab19-72773d64a402','~ばかり~','~ばかり~','N3','~ばかり~','“光、净、只……” [名]＋ばかり＋[动]：表示所列举的事物全部相同','“光、净、只……” [名]＋ばかり＋[动]：表示所列举的事物全部相同',NULL,245),
('2961e745-7452-4c0a-93fa-0f0d7adb72bf','~ばかりいます','~ばかりいます','N3','~ばかりいます','“老是，总是，光……，净……” [动(て形)]＋ばかり＋いる：表示总是发生同样的事情或总是进行同样的动作[反复]','“老是，总是，光……，净……” [动(て形)]＋ばかり＋いる：表示总是发生同样的事情或总是进行同样的动作[反复]',NULL,246),
('d46c9d08-ceb4-40ae-bcda-c97792f3bc8b','~始めます/~出します','~始めます/~出します','N3','~始めます/~出します','[动(连用形)]始める：表示动作或变化开始。\\n[动(连用形)]出す：表示突然出现了某情况。','[动(连用形)]始める：表示动作或变化开始。\\n[动(连用形)]出す：表示突然出现了某情况。',NULL,247),
('435e16f6-c5ee-4212-9c83-253d1d91b5bf','~はずがありません','~はずがありません','N3','~はずがありません','～はずが（は）ないです。 “不可能…”。 \\n“～はずです”的否定形式，表示根据某种理由做出某种否定性的推断。','～はずが（は）ないです。 “不可能…”。 \\n“～はずです”的否定形式，表示根据某种理由做出某种否定性的推断。',NULL,248),
('58cc8725-608d-4354-b68e-27628158485a','~はずです','~はずです','N3','~はずです','[小句(简体形)]はずです。 简体形：はずだ。 “应该是……” \\n表示说话人根据某种理由，做出某种合情合理的推断 \\n接续：[小句(简体形)/名词＋の/形2词干＋な]＋はずです。 \\n可以用于： \\n1) 说话人经历过但记忆不准确的事情； \\n2) 说话人认为确实如此，但和实际不一致的情况。','[小句(简体形)]はずです。 简体形：はずだ。 “应该是……” \\n表示说话人根据某种理由，做出某种合情合理的推断 \\n接续：[小句(简体形)/名词＋の/形2词干＋な]＋はずです。 \\n可以用于： \\n1) 说话人经历过但记忆不准确的事情； \\n2) 说话人认为确实如此，但和实际不一致的情况。',NULL,249),
('a27aa3b8-c56a-455e-9632-fecb7eaa2733','~までに','~までに','N3','~までに','“在~之前（发生或完成某动作）”， [名(时间)]までに 表示某动作或事态发生或完成的期间的终点。','“在~之前（发生或完成某动作）”， [名(时间)]までに 表示某动作或事态发生或完成的期间的终点。',NULL,250),
('d472089e-21b8-41f2-8f31-1c5a0bdb4f82','~まま，~','~まま，~','N3','~まま，~','[小句1(动词た形／ない形)]まま、小句2 表示将理应改变的某状态保持着去进行另外的动作。','[小句1(动词た形／ない形)]まま、小句2 表示将理应改变的某状态保持着去进行另外的动作。',NULL,251),
('99b7d62d-6c77-449b-a055-cc1f4fb721d8','~みたいです [推测]','~みたいです [推测]','N3','~みたいです [推测]','[小句(简体形)]/[名]/[形2词干]＋みたいです 表示根据说话人感知的某种情况进行推测，基本上与“～ようだ”同义。 用于比较随便的口语','[小句(简体形)]/[名]/[形2词干]＋みたいです 表示根据说话人感知的某种情况进行推测，基本上与“～ようだ”同义。 用于比较随便的口语',NULL,252),
('5c68476f-b680-4741-8371-a93f450e2905','~みたいです [比喻]','~みたいです [比喻]','N3','~みたいです [比喻]','[名]／[动(简体形)]+みたいです “好像…宛如…”，表示比喻时多与副词“まるで”呼应使用。语气更为随便，多用于口语；','[名]／[动(简体形)]+みたいです “好像…宛如…”，表示比喻时多与副词“まるで”呼应使用。语气更为随便，多用于口语；',NULL,253),
('af92c1cd-04c9-4ecd-86bd-0992f9b985c3','~も [超出预想]','~も [超出预想]','N3','~も [超出预想]','数量词+も+肯定形式：强调数量多，程度高；表示数量比预想的或应有的多','数量词+も+肯定形式：强调数量多，程度高；表示数量比预想的或应有的多',NULL,254),
('4aa2e08e-9644-473b-a087-e45182910520','~やすいです/~にくいです','~やすいです/~にくいです','N3','~やすいです/~にくいです','“易于……”/“难于……” [动(连用形)]+やすいです／にくいです。 表示某事物的性质。','“易于……”/“难于……” [动(连用形)]+やすいです／にくいです。 表示某事物的性质。',NULL,255),
('d368376f-d24a-4ee5-b490-1b52240dd6d5','~ようです [推测]','~ようです [推测]','N3','~ようです [推测]','[小句(简体形)]/[形2词干]+な/[名]+の ＋ようです 表示根据说话人感知的某种情况进行推测，“好像，似乎“。','[小句(简体形)]/[形2词干]+な/[名]+の ＋ようです 表示根据说话人感知的某种情况进行推测，“好像，似乎“。',NULL,256),
('142fea2f-5388-40ef-b83e-05b49702dc0b','~ようです [比喻]','~ようです [比喻]','N3','~ようです [比喻]','[名]＋の／[动(简体形)]+ようです　[比喻][示例] “好像…宛如…”，表示比喻时多与副词“まるで”呼应使用。语气更为正式，多用于正式的口语或书面语。','[名]＋の／[动(简体形)]+ようです　[比喻][示例] “好像…宛如…”，表示比喻时多与副词“まるで”呼应使用。语气更为正式，多用于正式的口语或书面语。',NULL,257),
('69e14d60-0cde-4c49-a931-dd5279696ff9','~ように，~','~ように，~','N3','~ように，~','[小句(基本形／ない形)]ように、[小句]　[目的] 表示“为了使前项状态成立，而有意识地做后项事情”。 一般前接非意志性动词，或意志性动词的可能形式','[小句(基本形／ない形)]ように、[小句]　[目的] 表示“为了使前项状态成立，而有意识地做后项事情”。 一般前接非意志性动词，或意志性动词的可能形式',NULL,258),
('4b513680-6826-436d-b7fb-eafe0a8f4f6f','~ようにします','~ようにします','N3','~ようにします','[小句(基本形／ない形)]ようにします：表示“努力做到……”。一般前接意志性动词 \\n[小句(基本形／ない形)]ようにしています：表示平时留心保持某习惯。','[小句(基本形／ない形)]ようにします：表示“努力做到……”。一般前接意志性动词 \\n[小句(基本形／ない形)]ようにしています：表示平时留心保持某习惯。',NULL,259),
('3057a3ab-ed2e-4b36-a70e-5a8dbf858834','~ようになります','~ようになります','N3','~ようになります','[小句(基本形／ない形)]ようになります：表示变化。 表示能力、状况、习惯等变成某种状态。 一般前接非意志性动词，或意志性动词的可能形式','[小句(基本形／ない形)]ようになります：表示变化。 表示能力、状况、习惯等变成某种状态。 一般前接非意志性动词，或意志性动词的可能形式',NULL,260),
('02501a54-d32c-431d-a81a-1087b5b1224e','~らしい~ [典型性]','~らしい~ [典型性]','N3','~らしい~ [典型性]','[名1]＋らしい＋[名2] 接尾词，前接名词，表示具有该事物应有的典型特征。 \\n多与副词“いかにも”（确实、的确、实在）呼应使用。 \\n若[名1]与[名2]为同一个名词时，表示“真正意义上的～”“像样的～”。','[名1]＋らしい＋[名2] 接尾词，前接名词，表示具有该事物应有的典型特征。 \\n多与副词“いかにも”（确实、的确、实在）呼应使用。 \\n若[名1]与[名2]为同一个名词时，表示“真正意义上的～”“像样的～”。',NULL,261),
('c6677f3e-0537-4460-9964-4d326a48c60a','~らしいです [推測] [传闻]','~らしいです [推測] [传闻]','N3','~らしいです [推測] [传闻]','[小句(简体形)]/[名词／二类形小句简体形式(去掉だ)]＋らしいです　 \\n1. 根据某种观察到的情况进行推测； \\n2. 婉转地叙述听来的消息。','[小句(简体形)]/[名词／二类形小句简体形式(去掉だ)]＋らしいです　 \\n1. 根据某种观察到的情况进行推测； \\n2. 婉转地叙述听来的消息。',NULL,262),
('4f7b89df-8cf8-44f2-bf05-da8ce6ef00e9','~られます','~られます','N3','~られます','变形相当于动词的被动形式。但在句中并不表示被动，而是表示对动作主体的敬意 ；同时，不同于被动语句，尊他语句的语序、助词等，都不改变。','变形相当于动词的被动形式。但在句中并不表示被动，而是表示对动作主体的敬意 ；同时，不同于被动语句，尊他语句的语序、助词等，都不改变。',NULL,263),
('3fd453fe-a055-45dc-bc10-c48d2f43b058','~んじゃないですか [婉转陈述意见的表达]','~んじゃないですか [婉转陈述意见的表达]','N3','~んじゃないですか [婉转陈述意见的表达]','表示婉转陈述意见，与“～のではないでしょうか”意思一样，礼貌程度略低。','表示婉转陈述意见，与“～のではないでしょうか”意思一样，礼貌程度略低。',NULL,264),
('338577ae-c373-4c3f-87d1-03953a7bb1a4','名词的修饰','名词的修饰','N4','名词的修饰','动词/形容词/动词小句/形容词小句修饰名词时，使用连体形式。连体形式：动词:简体形，形1:简体形，形2:词干+な，名词:名+の+名','动词/形容词/动词小句/形容词小句修饰名词时，使用连体形式。连体形式：动词:简体形，形1:简体形，形2:词干+な，名词:名+の+名',NULL,265),
('946ba33e-fc19-4cf2-bd94-c47f09303f68','自动词和他动词','自动词和他动词','N3','自动词和他动词','自动词：AがV自→ 描述客观现象、动作行为的结果 \\n他动词：Aが~をV他→ 描述主观的动作','自动词：AがV自→ 描述客观现象、动作行为的结果 \\n他动词：Aが~をV他→ 描述主观的动作',NULL,266),
('8d4403fd-f9a1-4cd8-87bd-a80b8ea92a2f','形容词的副词性用法','形容词的副词性用法','N3','形容词的副词性用法','接续：一类形容词：词尾い→く+动词  二类形容词：词干＋に+动词','接续：一类形容词：词尾い→く+动词  二类形容词：词干＋に+动词',NULL,267),
('0cb5795f-7700-4e22-bb61-7363da788238','形容词+さ','形容词+さ','N3','形容词+さ','构成表示某种状态的名词。\\n一类形词尾い→さ\\n二类形容词词干＋さ','构成表示某种状态的名词。\\n一类形词尾い→さ\\n二类形容词词干＋さ',NULL,268),
('245849d2-f90d-4a1b-88ae-541f5dfc1386','命令形','命令形','N3','命令形','用于向对方下命令。从基本形变起 \\n动1：->“え”段； \\n动2：“る”->“ろ”； \\n动3：“来(く)る”->“来(こ)い”，“する”->“しろ”。','用于向对方下命令。从基本形变起 \\n动1：->“え”段； \\n动2：“る”->“ろ”； \\n动3：“来(く)る”->“来(こ)い”，“する”->“しろ”。',NULL,269),
('7ed08a04-17d6-4663-aab9-9bab36372586','意志形','意志形','N3','意志形','说话人当场表示自己的决心、意志。从基本形变起 \\n动1：->“お”段上的长音； \\n动2：“る”->“よう”； \\n动3：する→しよう；くる→こよう；','说话人当场表示自己的决心、意志。从基本形变起 \\n动1：->“お”段上的长音； \\n动2：“る”->“よう”； \\n动3：する→しよう；くる→こよう；',NULL,270),
('e0fe5f12-0cfc-4744-9fcc-18a02c381bf5','ば形','ば形','N3','ば形','动1：->“え”段+“ば”\\n动2：“る”->“れば”\\n动3：“来る”->“来れば”，“する”->“すれば”\\n形1：“い”->“ければ”','动1：->“え”段+“ば”\\n动2：“る”->“れば”\\n动3：“来る”->“来れば”，“する”->“すれば”\\n形1：“い”->“ければ”',NULL,271),
('f26be8db-e7f1-412d-8b97-51a3ddf19ada','可能形式','可能形式','N3','可能形式','活用：\\n动1：->“え”段+“る”\\n动2：“る”->“られる”\\n动3：“来る”->“来られる”，“する”->“できる”\\n用法：可能形式与“～ことができます”意义相同，即表示能力或条件允许或可能性。','活用：\\n动1：->“え”段+“る”\\n动2：“る”->“られる”\\n动3：“来る”->“来られる”，“する”->“できる”\\n用法：可能形式与“～ことができます”意义相同，即表示能力或条件允许或可能性。',NULL,272),
('405eb8b2-096e-4321-8c30-285835012f6b','被动形式','被动形式','N3','被动形式','基于ない形\\n动1：“ない”->“れる”\\n动2：“ない”->“られる”\\n动3：“来る”->“来られる”，“する”->“される”','基于ない形\\n动1：“ない”->“れる”\\n动2：“ない”->“られる”\\n动3：“来る”->“来られる”，“する”->“される”',NULL,273),
('9990123b-e583-42fd-a3b4-1bc1d3528918','使役形式','使役形式','N3','使役形式','使役主体强制、指示、放任、许可动作主体做某事。“让…做…”。\\n基于ない形\\n动1：“ない”->“せる”\\n动2：“ない”->“させる”\\n动3：“来る”->“来(こ)させる”，“する”->“させる”','使役主体强制、指示、放任、许可动作主体做某事。“让…做…”。\\n基于ない形\\n动1：“ない”->“せる”\\n动2：“ない”->“させる”\\n动3：“来る”->“来(こ)させる”，“する”->“させる”',NULL,274),
('932dbff4-6974-4f72-bbe0-89b833457f1a','敬语','敬语','N3','敬语','分为以下三类： \\n尊他语：通过抬高话题中的动作主体，而对动作主体表示敬意。 \\n自谦语：通过贬低动作主体（己方），从而相对地对动作接受者或动作涉及的对象表示敬意。 \\n礼貌语：通过使用客气的词语，对听话人表示敬意。','分为以下三类： \\n尊他语：通过抬高话题中的动作主体，而对动作主体表示敬意。 \\n自谦语：通过贬低动作主体（己方），从而相对地对动作接受者或动作涉及的对象表示敬意。 \\n礼貌语：通过使用客气的词语，对听话人表示敬意。',NULL,275),
('2d43b084-bba4-4cb9-955e-1b06200f0076','尊他语','尊他语','N3','尊他语','尊他语：通过抬高话题中的动作主体，而对动作主体表示敬意。 \\n敬语使用的场合： \\n1) 与比自己身份地位高的人（老师、上级或年长者等）说话时； \\n2) 与陌生人或关系不密切的人说话时； \\n3) 在郑重场合说话时。','尊他语：通过抬高话题中的动作主体，而对动作主体表示敬意。 \\n敬语使用的场合： \\n1) 与比自己身份地位高的人（老师、上级或年长者等）说话时； \\n2) 与陌生人或关系不密切的人说话时； \\n3) 在郑重场合说话时。',NULL,276),
('fb7be6a6-ffd2-4e8f-8ad2-0deb0ca938e0','自谦语','自谦语','N3','自谦语','通过贬低动作主体（己方），从而相对地对动作接受者或动作涉及的对象表示敬意。','通过贬低动作主体（己方），从而相对地对动作接受者或动作涉及的对象表示敬意。',NULL,277),
('5516f30b-ab7e-4588-9465-88ec7d9ca4c6','~は~られます','~は~られます','N3','~は~られます','直接被动句[人2 主语]は([人1 动作施加者]に)[动] (ら)れます。 主动句中的宾语（动作对象），挪到被动句中作主语。 被动句中，主语承受了动作施加者的某个动作或影响，是客观叙述，不带感情色彩，动作主体（动作施加者）用“に”表示。','直接被动句[人2 主语]は([人1 动作施加者]に)[动] (ら)れます。 主动句中的宾语（动作对象），挪到被动句中作主语。 被动句中，主语承受了动作施加者的某个动作或影响，是客观叙述，不带感情色彩，动作主体（动作施加者）用“に”表示。',NULL,278),
('a50b2e95-2b3a-43bd-b6f8-05b07c070a83','使役被动形式','使役被动形式','N3','使役被动形式','表示被迫做某事\\n基于ない形\\n动1：“ない”→“される”，“さない”->“させられる”\\n动2：“ない”→“させられる”\\n动3：“来る”→“来(こ)させられる”，“する”->“させられる”','表示被迫做某事\\n基于ない形\\n动1：“ない”→“される”，“さない”->“させられる”\\n动2：“ない”→“させられる”\\n动3：“来る”→“来(こ)させられる”，“する”->“させられる”',NULL,279),
('64e37379-383a-4790-bacf-17521d972b13','いくら~ても/いかに~ても','いくら~ても/いかに~ても','N3','いくら~ても/いかに~ても','逆接','逆接',NULL,280),
