('4175f6d3-ae1a-4b60-88da-b42432ff99f3','~ということは，~ということだ','~ということは，~ということだ','N1','~ということは，~ということだ','「～ということだ」表示解说或逻辑结果\\n被解说的事项可用「～ということは」引出。','「～ということだ」表示解说或逻辑结果\\n被解说的事项可用「～ということは」引出。',NULL,497),
('96841734-a396-4893-b045-be42e34fdb40','~というより(も)','~というより(も)','N1','~というより(も)','后项常跟「むしろ、～ほうが」呼应','后项常跟「むしろ、～ほうが」呼应',NULL,498),
('20433948-2a2e-4828-82e2-03e6e8354ffe','~といったもの','~といったもの','N1','~といったもの','表示列举','表示列举',NULL,499),
('119e45d0-fb19-4b0b-bba0-f6a0be6f078d','~といっても過言ではない','~といっても過言ではない','N1','~といっても過言ではない','简体小句＋といっても過言ではない','简体小句＋といっても過言ではない',NULL,500);

