('c827a428-377b-4d23-9b38-6876f6cbf13b','~どころか','~どころか','N1','~どころか','【動詞基本形／形容詞／名詞】＋どころか','【動詞基本形／形容詞／名詞】＋どころか',NULL,505),
('9a91a2dc-e816-4e08-a542-c6d860e4bb8e','~ところがある','~ところがある','N1','~ところがある','【连体形】＋ところがある\\n是一种比较婉转的表达','【连体形】＋ところがある\\n是一种比较婉转的表达',NULL,506),
('2a56e20b-5ad1-45f1-99b5-5d6efae59fce','~どころではない','~どころではない','N1','~どころではない','【动词基本形／形容词】＋どころではない\\n【二类形容词词干／名词】＋どころではない\\n由于客观原因，否定语气','【动词基本形／形容词】＋どころではない\\n【二类形容词词干／名词】＋どころではない\\n由于客观原因，否定语气',NULL,507),
('93f28452-67b4-4a43-af53-1be971924ddb','~としても，~','~としても，~','N1','~としても，~','［小句（简体形式）］＋としても\\n［二类形容词／名词＋だ］＋としても','［小句（简体形式）］＋としても\\n［二类形容词／名词＋だ］＋としても',NULL,508),
('5cee7633-2434-4a77-9bd5-e93ad668d5fc','~とすれば/~とすると/~としたら','~とすれば/~とすると/~としたら','N1','~とすれば/~とすると/~としたら','「基本形」＋とすると／とすれば／としたら\\n「基本形／名詞」＋となると／となれば／となったら','「基本形」＋とすると／とすれば／としたら\\n「基本形／名詞」＋となると／となれば／となったら',NULL,509),
('5b053a70-cd65-48dd-a096-e0cbc68e6237','~と同時に','~と同時に','N1','~と同時に','［动词基本形／一类形容词］＋と同時に\\n［名词／二类形容词］＋である＋と同時に\\n※前后主语不同也可以使用','［动词基本形／一类形容词］＋と同時に\\n［名词／二类形容词］＋である＋と同時に\\n※前后主语不同也可以使用',NULL,510),
('7e973a7a-ca3c-410f-934e-9bc8c9776f63','~となると','~となると','N1','~となると','「基本形／名詞」＋となると','「基本形／名詞」＋となると',NULL,511),
('f49f9003-176d-46e4-b564-2caed1fdf4dc','~とはいうものの','~とはいうものの','N1','~とはいうものの','前接连体形式：\\n［二类形容词］＋な／である＋もの\\n［名词］＋である＋ものの\\n［简体小句／名词］＋とはいうものの\\n表示转折，相当于「けれども」。\\n与「とはいっても」相似，也可单独使用。','前接连体形式：\\n［二类形容词］＋な／である＋もの\\n［名词］＋である＋ものの\\n［简体小句／名词］＋とはいうものの\\n表示转折，相当于「けれども」。\\n与「とはいっても」相似，也可单独使用。',NULL,512),
('401db7ac-91a9-4a45-8ea7-8f2c7f89fdc0','~とまでいわれた','~とまでいわれた','N2','~とまでいわれた','同样的助词还有「でも」「さえ」， 分别添加举例和极端的意思。','同样的助词还有「でも」「さえ」， 分别添加举例和极端的意思。',NULL,513),
('5e0329d6-8bfd-40a9-800f-52e53f484418','~ないかぎり/~ないことには/~なくては','~ないかぎり/~ないことには/~なくては','N1','~ないかぎり/~ないことには/~なくては','只要不……就……','只要不……就……',NULL,514),
('afeb7281-aaab-4f13-8162-9bd221fa8e4f','~ないことはない','~ないことはない','N1','~ないことはない','［動詞否定形］＋ないことはない','［動詞否定形］＋ないことはない',NULL,515),
('0d7577be-b6af-4afd-afd0-c5da2d14c5c0','~ないと','~ないと','N1','~ないと','「～ないといけない」等形式省略了后半句的说法','「～ないといけない」等形式省略了后半句的说法',NULL,516),
('d2732117-fa6b-41b2-a431-81a58cee13e6','~ないものでしようか/~ないでしようか','~ないものでしようか/~ないでしようか','N1','~ないものでしようか/~ないでしようか','「～ないものでしょうか」是希望某事得以实现的否定疑问句。\\n「～ないでしょうか」也同样表示希望得到必要的东西，但不可以用于单纯询问是否存在某事物。','「～ないものでしょうか」是希望某事得以实现的否定疑问句。\\n「～ないでしょうか」也同样表示希望得到必要的东西，但不可以用于单纯询问是否存在某事物。',NULL,517),
('816b7150-0751-4b4a-97c5-40ac946cfc58','~中(で)，~','~中(で)，~','N1','~中(で)，~','［動詞基本形／形容詞］＋中（なか）、\\n［名詞＋の］＋中（なか）\\n「～中（なか）」在此表示某事态发生的背景状态','［動詞基本形／形容詞］＋中（なか）、\\n［名詞＋の］＋中（なか）\\n「～中（なか）」在此表示某事态发生的背景状态',NULL,518),
('e3f1c00c-352d-49e9-a080-9a4604871108','~ながら(も)','~ながら(も)','N1','~ながら(も)','［动词ます形去ます］＋ながら（も）\\n［一类形容词］＋ながら（も）\\n［名词／二类形容词］（＋であり）＋ながら（も）','［动词ます形去ます］＋ながら（も）\\n［一类形容词］＋ながら（も）\\n［名词／二类形容词］（＋であり）＋ながら（も）',NULL,519),
('6868f72d-f924-465c-a1e5-581026aa1468','~なさいませんか','~なさいませんか','N1','~なさいませんか','「なさる」【他一】＝「する」的尊他语形式。\\n「なさった」「なさって」「なさらない」「なさいます」「なさい」','「なさる」【他一】＝「する」的尊他语形式。\\n「なさった」「なさって」「なさらない」「なさいます」「なさい」',NULL,520),
('500f491a-bb7c-4de1-bf5a-d147a40b4051','~なしで','~なしで','N1','~なしで','「ない」的文言形态，接在名词之后表示没有或缺乏某事物。\\n常用「なしに」「なしで」的形式，前者表示状态，后者表示方法手段。','「ない」的文言形态，接在名词之后表示没有或缺乏某事物。\\n常用「なしに」「なしで」的形式，前者表示状态，后者表示方法手段。',NULL,521),
('042873e4-eb5b-428f-8846-f5b451ad9543','~なしに(は)/~なしで(は)/~なくして','~なしに(は)/~なしで(は)/~なくして','N1','~なしに(は)/~なしで(は)/~なくして','「Aなしには／なしでは／なくしてB」表示A是实现B的必不可少的条件。','「Aなしには／なしでは／なくしてB」表示A是实现B的必不可少的条件。',NULL,522),
('2a4f42c7-a794-44f7-9a1a-8cc4036ab6ab','何しろ~(な)ので','何しろ~(な)ので','N1','何しろ~(な)ので','有时与表示理由的表达呼应，强调这种理由','有时与表示理由的表达呼应，强调这种理由',NULL,523),
('f918fcee-3d91-4d49-bf52-1cb0b2228c05','~なら【主题】','~なら【主题】','N1','~なら【主题】','「なら」原本表示假定，也可以表示接过他人的话题。\\n此外也可以用于提出一个代替的方案。一般不能用于否定。','「なら」原本表示假定，也可以表示接过他人的话题。\\n此外也可以用于提出一个代替的方案。一般不能用于否定。',NULL,524),
('32688255-46e3-4194-abae-a4ce41feb7f8','~ならでは(の)','~ならでは(の)','N1','~ならでは(の)','［名詞］＋ならでは（の）\\n现在一般都以「～ならではの」的形式出现，偶尔也有「～ならでは～ない」的形式，意思相同。','［名詞］＋ならでは（の）\\n现在一般都以「～ならではの」的形式出现，偶尔也有「～ならでは～ない」的形式，意思相同。',NULL,525),
('4728e334-0ced-412d-a740-19f3872968ba','~ならぬ','~ならぬ','N1','~ならぬ','①断定助动词「なり」＋否定助动词「ぬ」＝「～ではない」\\n②动词「なる」＋否定助动词「ぬ」＝「～ならない」','①断定助动词「なり」＋否定助动词「ぬ」＝「～ではない」\\n②动词「なる」＋否定助动词「ぬ」＝「～ならない」',NULL,526),
('c87123b4-7ac6-4ffb-9636-bbab3d40ea9b','~ならびに~','~ならびに~','N1','~ならびに~','「～ならびに（並びに）」是书面语\\n※ 不能接不同类的事物（如：「天と地」不能说成「天ならびに地」）','「～ならびに（並びに）」是书面语\\n※ 不能接不同类的事物（如：「天と地」不能说成「天ならびに地」）',NULL,527),
('b78f68c9-d215-461d-9746-3918e4aa28b5','~なりに','~なりに','N1','~なりに','［名詞］＋なりに／なりの','［名詞］＋なりに／なりの',NULL,528),
('9eae5bd7-ecc6-47da-acc6-ae757013931d','~なればなるほど','~なればなるほど','N1','~なればなるほど','［动词／一类形容词ば形＋基本形＋ほど］\\n［名词／二类形容词词干－であれば＋ある＋ほど］','［动词／一类形容词ば形＋基本形＋ほど］\\n［名词／二类形容词词干－であれば＋ある＋ほど］',NULL,529),
('a8a2e3e7-e09a-44e5-8c8e-ba025a301327','なんて~んだろう','なんて~んだろう','N1','なんて~んだろう','「なんという」的口语\\n句尾不仅限于「んだろう」，也可用「だろう」。','「なんという」的口语\\n句尾不仅限于「んだろう」，也可用「だろう」。',NULL,530),
('1c93983d-b314-4e45-bd47-72ab34eb806c','~なんていうもの','~なんていうもの','N1','~なんていうもの','相当于「などというもの」「などのようなもの」在口语中比较随便的说法，用于从诸多事物中举例说明。','相当于「などというもの」「などのようなもの」在口语中比较随便的说法，用于从诸多事物中举例说明。',NULL,531),
('09942db0-5b5a-43e4-a82b-e33954499198','~なんてことはない','~なんてことはない','N1','~なんてことはない','只是在「～ことはない」前面加上「なんて」','只是在「～ことはない」前面加上「なんて」',NULL,532),
('53b978a5-8360-4b81-9229-5480570bbbac','~に合う~','~に合う~','N1','~に合う~','【名詞】＋に合う','【名詞】＋に合う',NULL,533),
('b25bfe3c-aabf-44a5-b9c1-2c5118533ee8','~にあたって','~にあたって','N1','~にあたって','【動詞基本形／名詞】＋にあたって\\n類似表現：「～に際して」\\n表示在某个特殊的机会和情况下……。','【動詞基本形／名詞】＋にあたって\\n類似表現：「～に際して」\\n表示在某个特殊的机会和情况下……。',NULL,534),
('4fc9d32f-bf1f-4ede-8ac4-6ebca826ef96','~に至る','~に至る','N1','~に至る','【小句（简体形式）／名詞】＋に至る\\n※ 用于书面语。','【小句（简体形式）／名詞】＋に至る\\n※ 用于书面语。',NULL,535),
('47baed64-1edd-48e8-a99f-7f8540ba84aa','~こ至るまで','~こ至るまで','N1','~こ至るまで','【名詞】＋に至るまで\\n前面常与「～をはじめ」「～から」「～はもちろん」等呼应使用。','【名詞】＋に至るまで\\n前面常与「～をはじめ」「～から」「～はもちろん」等呼应使用。',NULL,536),
('4509ea88-6265-4f4d-a8e6-c358cbd0a834','~に応じた/~に応じて','~に応じた/~に応じて','N1','~に応じた/~に応じて','【名詞】＋に応じた／に応じて\\n有时可与「によって」互换','【名詞】＋に応じた／に応じて\\n有时可与「によって」互换',NULL,537),
('23003c49-ada9-487b-bd29-317ead5bc10c','~におかれましては','~におかれましては','N2','~におかれましては','【名詞】＋におかれましては\\n用于表示主体，尊他语表达方式，常用于书信中。','【名詞】＋におかれましては\\n用于表示主体，尊他语表达方式，常用于书信中。',NULL,538),
('69e08538-d07a-4a03-8b16-9d20b9b152b3','~に終わる','~に終わる','N1','~に終わる','【名詞】＋に終わる\\n用于某件事的结果事与愿违的情况\\n【名詞】＋のうちに終わる 则用于积极的场合','【名詞】＋に終わる\\n用于某件事的结果事与愿违的情况\\n【名詞】＋のうちに終わる 则用于积极的场合',NULL,539),
('cf256f2c-446a-454f-9927-d2fa668eda89','~に関わる','~に関わる','N1','~に関わる','【名詞】＋に関わる\\n多用于重要、重大的事情','【名詞】＋に関わる\\n多用于重要、重大的事情',NULL,540),
('bc9139ca-00f5-4015-99b3-e38e7bc742f6','~に決まっている','~に決まっている','N1','~に決まっている','【小句（简体形式）】＋に決まっている\\n【二类形容词／名词】＋に決まっている\\n表示说话人很确定、很有自信的判断','【小句（简体形式）】＋に決まっている\\n【二类形容词／名词】＋に決まっている\\n表示说话人很确定、很有自信的判断',NULL,541),
('e9907084-0454-40db-bb38-4810f36d557c','~に加え(て)','~に加え(て)','N1','~に加え(て)','【名詞】＋に加え（て）','【名詞】＋に加え（て）',NULL,542),
('d5628b10-1c9c-4f2d-a301-94f51ba3a707','~に際して','~に際して','N1','~に際して','【动作性名词】＋に際して','【动作性名词】＋に際して',NULL,543),
('ce5e41f3-8ea8-405f-a4d6-f8cd5a54abfc','~に先立って','~に先立って','N1','~に先立って','【名詞／動詞基本形】＋に先立って／に先立つ\\n多用于在某事开始之前事先做准备','【名詞／動詞基本形】＋に先立って／に先立つ\\n多用于在某事开始之前事先做准备',NULL,544),
('91697e23-57cf-491b-aefe-e553c850087f','~にしたがって','~にしたがって','N1','~にしたがって','【動詞基本形／名詞】＋にしたがって\\n动词「従う（したがう）」','【動詞基本形／名詞】＋にしたがって\\n动词「従う（したがう）」',NULL,545),
('66ed51d0-5eea-42b2-8f82-44d62a5842ed','~にしても/~にしろ/~にせよ','~にしても/~にしろ/~にせよ','N1','~にしても/~にしろ/~にせよ','【小句（简体形式）／名詞】＋にしても／にしろ／にせよ','【小句（简体形式）／名詞】＋にしても／にしろ／にせよ',NULL,546),
('1d8411dd-8d13-4869-bb0c-0ad2b41c7ee7','~にすぎない','~にすぎない','N1','~にすぎない','［動詞简体形／名詞］＋にすぎない','［動詞简体形／名詞］＋にすぎない',NULL,547),
('99dcae20-e8d6-4d11-990e-f2dd7ee94de9','~にすら','~にすら','N1','~にすら','助词「に」＋表示极端的「すら」','助词「に」＋表示极端的「すら」',NULL,548),
('e39ed576-6b80-4403-aa0a-ff775a9a5de5','~につれて','~につれて','N1','~につれて','和「～にしたがって」意思相近，有时可以互换。\\n但「にしたがって」倾向于因果关系，「につれて」倾向于自然而然的变化。','和「～にしたがって」意思相近，有时可以互换。\\n但「にしたがって」倾向于因果关系，「につれて」倾向于自然而然的变化。',NULL,549),
